from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['cms']
profiles_collection = db['user_profiles']

@app.route('/create_profile', methods=['POST'])
def create_profile():
    profile_data = request.json
    result = profiles_collection.insert_one(profile_data)
    return jsonify({'inserted_id': str(result.inserted_id)})

@app.route('/get_profiles', methods=['GET'])
def get_profiles():
    profiles = list(profiles_collection.find())
    for profile in profiles:
        profile['_id'] = str(profile['_id'])
    return jsonify(profiles)

@app.route('/profile_query', methods=['POST'])
def profile_query():
    query = request.json
    profiles = list(profiles_collection.find(query))
    for profile in profiles:
        profile['_id'] = str(profile['_id'])
    return jsonify(profiles)

@app.route('/profile_aggregate', methods=['POST'])
def profile_aggregate():
    pipeline = request.json
    result = list(profiles_collection.aggregate(pipeline))
    for item in result:
        item['_id'] = str(item['_id'])
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)